var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"쿨럭……!","JPN":"ゴホッ……！","ENG":"*Cough*...!","TWN":"咳咳……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자…… 님…….","JPN":"救世主……様……","ENG":"Sa...vior...","TWN":"救贖者…大人…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아? 정신이 들어?","JPN":"ルクレシア？　気が付いた？","ENG":"Lucrecia? Are you okay?","TWN":"露可蕾西亞？你醒了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"앞이……. 더 이상, 보이지 않아요.","JPN":"前が……まったく、見えません。","ENG":"I... I can't see anymore...","TWN":"我……看不見了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"손…… 잡아 주시면…….","JPN":"て……手を握ってください……","ENG":"Hold... my hand... Please...","TWN":"請抓住……我的手……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……떨고 계시네요. 구원자님.","JPN":"……震えていますね。救世主様。","ENG":"...You're shaking... Savior...","TWN":"……您在發抖，救贖者大人。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"어떤 표정을 짓고 계실지, 알 것 같아요.","JPN":"今どんな顔をされているか、わかる気がします。","ENG":"I can imagine... what your face will be like...","TWN":"我好像能知道，您現在是什麼表情。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미안해, 루크레시아.","JPN":"ごめん、ルクレシア。","ENG":"I'm sorry, Lucrecia.","TWN":"對不起，露可蕾西亞。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"상처가 아물지 않아. 아무리 힘을 써도, 전부 새어나가 버려.","JPN":"傷が癒せない。いくら力を注いでも、すべて滲み出てしまう。","ENG":"The wound won't heal. No matter how much power I use, it all fades away.","TWN":"傷口沒法癒合，不管我填補上多少力量，都會漏出去。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미안해. 이럴 생각은, 이, 이럴 생각은, 아니었는데……","JPN":"ごめん。こんなつもりじゃ、こ、こんなつもりじゃ、なかったんだ……","ENG":"I'm so sorry. I-I... n-never meant any of this...","TWN":"對不起，我本來，我本來不想這樣的……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"내가, 클리포트 게임을 선언하기 전에 사실대로 말했더라면…….","JPN":"僕が、クリフォトゲームを宣言する前に本当のことを話していたら……","ENG":"If only I had told you the truth before declaring the Qliphoth Game...","TWN":"如果，我在宣告逆卡巴拉遊戲之前就坦白的話……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아뇨.","JPN":"いいえ。","ENG":"No.","TWN":"不。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이방인들을 위해, 그렇게까지 괴로워하실 줄 몰랐던 제 부덕함 탓이지요.","JPN":"異邦人のために、そこまで思い悩まれると思い及ばなかった私の落ち度です。","ENG":"It is my fault. I didn't know you would feel such remorse for the outsiders...","TWN":"是我的錯，我不知道您會為了外邦人而如此地痛苦。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"만약 제가 먼저 알아챘더라면…… 어떻게든…….","JPN":"もっと私が早くに気づいていれば……なんとか……","ENG":"Had I known sooner... I would have...","TWN":"如果我早點發現……無論如何……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아니야, 나는……. 나는 그저…….","JPN":"いや、僕は……僕はただ……","ENG":"No, I... I just...","TWN":"不是的，我……我只是……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"좀 더 나은 길을 찾고 싶었어…. 아무도 다치지 않길 바라서……. 그래서…….","JPN":"より良い選択肢を見つけたかった……誰にも傷ついてほしくなくて……だから……","ENG":"I just wanted to find a better solution... I didn't want anyone getting hurt... So...","TWN":"想找一條更好的路……一條沒有人會受傷的路……所以……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…저에게 지팡이를 주실 때도 그런 마음이셨죠.","JPN":"……私に杖を渡されたときも、そんな思いだったのでしょうね。","ENG":"...You felt that way when the staff was bestowed upon me.","TWN":"…您把復活之杖交給我的時候也是那種心情吧？"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 뒤로 언제나 당신의 뒤를 따르겠다고 생각했는데…….","JPN":"その時から私は、いつまでもあなたの後ろをついていくと決めたのに……","ENG":"After that, I vowed to follow you no matter what...","TWN":"從那以後，我就決定要一直追隨您的腳步……"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이번에는, 저도 모르게 앞질러 갔나 봐요.","JPN":"今回は、知らぬうちに追い越してしまっていたようです。","ENG":"But this time, it seems that I went too far.","TWN":"這次，我好像不知不覺地搶先了一步呢。"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"세상 물정 모르고 신전을 뛰쳐 나왔던 노예 계집에게…… 잘 어울리는 최후네요.","JPN":"世間を知らず、神殿から飛び出してきた奴隷の娘には……お似合いの最期だと思います。","ENG":"A well-deserved demise... for a slave... who ran away from the temple.","TWN":"對於我這個不懂人情世故，逃出神殿的奴隸來說……這是最好的結局了吧？"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아…….","JPN":"ルクレシア……","ENG":"Lucrecia...","TWN":"露可蕾西亞……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"However...","TWN":"不過……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"못난 저이지만, 누구보다 잘 알고 있답니다.","JPN":"未熟な私ですが、誰よりも一番よくわかっていることがあります。","ENG":"Despite my circumstances, I know better than anyone else...","TWN":"雖然我很沒出息，但我很清楚。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"성역에 구원을 가져와 주실 분이 누구신지….","JPN":"聖域に救いをもたらしてくださるのが、誰なのか……","ENG":"Who will bring salvation upon the sanctuary...","TWN":"誰會拯救聖域……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제가 그 날 보았던 광명이…. 누구에게서 비롯되었는지.","JPN":"私があの日見た光明が……誰から放たれていたのか。","ENG":"Whose light it was... that I saw that day.","TWN":"我那天看到的光明……來自於誰。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그러니까 울지 마세요.","JPN":"だから、泣かないでください。","ENG":"So please... don't cry...","TWN":"所以，請您不要哭泣。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"나의…….","JPN":"私の……","ENG":"My...","TWN":"我的……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"구원자님.","JPN":"救世主様。","ENG":"Savior.","TWN":"救贖者大人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};